class Network{constructor(s){this.isOnline=!1,this.elem=s}showOffline(){this.isOnline=!1,this.elem.innerHTML='<span class="red"> </span>'}showOnline(){this.isOnline=!0,this.elem.innerHTML='<span class="green"> </span>'}statusListener=s=>{this.isOnline&&"disconnected"===s.value?this.showOffline():this.isOnline||"connected"!==s.value||this.showOnline()}}